import{_ as a,o as i,c as n,a3 as t}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse(`{"title":"A Transitional Provisions","description":"","frontmatter":{"title":"A Transitional Provisions","eba":"Children's Services Award 2010","topics":["schedules","transitional"]},"headers":[],"relativePath":"ebas/childrens-services/schedules/a-transitional-provisions.md","filePath":"ebas/childrens-services/schedules/a-transitional-provisions.md"}`),o={name:"ebas/childrens-services/schedules/a-transitional-provisions.md"};function r(l,e,s,p,m,h){return i(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="a-transitional-provisions" tabindex="-1">A Transitional Provisions <a class="header-anchor" href="#a-transitional-provisions" aria-label="Permalink to &quot;A Transitional Provisions&quot;">​</a></h1><ol><li><p>General</p><ol><li><p>The provisions of this schedule deal with minimum obligations only.</p></li><li><p>The provisions of this schedule are to be applied:</p><p>a. when there is a difference, in money or percentage terms, between a provision in a relevant transitional minimum wage instrument (including the transitional default casual loading) or award-based transitional instrument on the one hand and an equivalent provision in this award on the other;</p><p>b. when a loading or penalty in a relevant transitional minimum wage instrument or award-based transitional instrument has no equivalent provision in this award;</p><p>c. when a loading or penalty in this award has no equivalent provision in a relevant transitional minimum wage instrument or award-based transitional instrument; or</p><p>d. when there is a loading or penalty in this award but there is no relevant transitional minimum wage instrument or award-based transitional instrument.</p></li></ol></li><li><p>To avoid doubt, this schedule operates subject to the transitional pay equity order referred to in <a href="/eba/ebas/childrens-services/wages/14-minimum-wages.html">clause 14</a> of this award.</p></li><li><p>Minimum wages -- existing minimum wage lower</p><ol><li><p>The following transitional arrangements apply to an employer which, immediately prior to 1 January 2010:</p><p>a. was obliged,</p><p>b. but for the operation of an agreement-based transitional instrument or an enterprise agreement would have been obliged, or</p><p>c. if it had been an employer in the industry or of the occupations covered by this award would have been obliged</p></li></ol></li></ol><p>by a transitional minimum wage instrument and/or an award-based transitional instrument to pay a minimum wage lower than that in this award for any classification of employee.</p><ol><li><p>In this clause minimum wage includes:</p><p>a. a minimum wage for a junior employee, an employee to whom training arrangements apply and an employee with a disability;</p><p>b. a piecework rate; and</p><p>c. any applicable industry allowance.</p></li><li><p>Prior to the first full pay period on or after 1 July 2010 the employer must pay no less than the minimum wage in the relevant transitional minimum wage instrument and/or award-based transitional instrument for the classification concerned.</p></li><li><p>The difference between the minimum wage for the classification in this award and the minimum wage in clause A.2.3 is referred to as the transitional amount.</p></li><li><p>From the following dates the employer must pay no less than the minimum wage for the classification in this award minus the specified proportion of the transitional amount:</p></li></ol><p><strong>First full pay period on or after</strong></p><hr><p>1 July 2010 80% 1 July 2011 60% 1 July 2012 40% 1 July 2013 20%</p><ol><li><p>The employer must apply any increase in minimum wages in this award resulting from an annual wage review.</p></li><li><p>These provisions cease to operate from the beginning of the first full pay period on or after 1 July 2014.</p></li><li><p>Minimum wages -- existing minimum wage higher</p><ol><li><p>The following transitional arrangements apply to an employer which, immediately prior to 1 January 2010:</p><p>a. was obliged,</p><p>b. but for the operation of an agreement-based transitional instrument or an enterprise agreement would have been obliged, or</p><p>c. if it had been an employer in the industry or of the occupations covered by this award would have been obliged</p></li></ol></li></ol><p>by a transitional minimum wage instrument and/or an award-based transitional instrument to pay a minimum wage higher than that in this award for any classification of employee.</p><ol><li><p>In this clause minimum wage includes:</p><p>a. a minimum wage for a junior employee, an employee to whom training arrangements apply and an employee with a disability;</p><p>b. a piecework rate; and</p><p>c. any applicable industry allowance.</p></li><li><p>Prior to the first full pay period on or after 1 July 2010 the employer must pay no less than the minimum wage in the relevant transitional minimum wage instrument and/or award-based transitional instrument for the classification concerned.</p></li><li><p>The difference between the minimum wage for the classification in this award and the minimum wage in clause A.3.3 is referred to as the transitional amount.</p></li><li><p>From the following dates the employer must pay no less than the minimum wage for the classification in this award plus the specified proportion of the transitional amount:</p></li></ol><p><strong>First full pay period on or after</strong></p><hr><p>1 July 2010 80% 1 July 2011 60% 1 July 2012 40% 1 July 2013 20%</p><ol><li><p>The employer must apply any increase in minimum wages in this award resulting from an annual wage review. If the transitional amount is equal to or less than any increase in minimum wages resulting from the 2010 annual wage review the transitional amount is to be set off against the increase and the other provisions of this clause will not apply.</p></li><li><p>New South Wales, Western Australia and Tasmania -- Other than Division 2B State award employers</p></li></ol><p>The following transitional arrangements apply to an employer in New South Wales, Western Australia and Tasmania which, immediately prior to 1 January 2010:</p><p>a. was obliged,</p><p>b. but for the operation of an agreement-based transitional instrument or an enterprise agreement would have been obliged, or</p><p>c. if it had been an employer in the industry or of the occupations covered by this award would have been obliged</p><p>by a transitional minimum wage instrument and/or an award-based transitional instrument to pay a minimum wage higher than that in this award for an employee engaged in a classification lower than Children&#39;s Services Employee Level 3.1 and all classifications of Support Worker in Tasmania and Western Australia, and for all classifications in New South Wales.</p><p>The employer must:</p><p>i. continue to pay no less than the minimum wage in the transitional minimum wage instrument and/or award-based transitional instrument; and</p><p>ii. apply any increase in minimum wages in this award resulting from an annual wage review.</p><ol><li>New South Wales and Tasmania -- Division 2B State award employers</li></ol><p>The following transitional arrangements apply to an employer in New South Wales and Tasmania which, immediately prior to 1 January 2011:</p><p>a. was obliged,</p><p>b. but for the operation of a Division 2B State employment agreement or an enterprise agreement would have been obliged, or</p><p>c. if it had been an employer in the industry or of the occupations covered by this award would have been obliged</p><p>by a Division 2B State award to pay a minimum wage higher than that in this award for an employee engaged in a classification lower than Children&#39;s Services Employee Level 3.1 and all classifications of Support Worker in Tasmania and for all classifications in New South Wales.</p><p>The employer must:</p><p>i. continue to pay no less than the minimum wage in the Division 2B State award and</p><p>ii. apply any increase in minimum wages in this award resulting from an annual wage review.</p><ol><li><p>These provisions cease to operate from the beginning of the first full pay period on or after 1 July 2014.</p></li><li><p>Loadings and penalty rates</p></li></ol><p>For the purposes of this schedule loading or penalty means a:</p><ul><li><p>casual or part-time loading;</p></li><li><p>Saturday, Sunday, public holiday, evening or other penalty;</p></li><li><p>shift allowance/penalty.</p><ol><li><p>Loadings and penalty rates -- existing loading or penalty rate lower</p><ol><li><p>The following transitional arrangements apply to an employer which, immediately prior to 1 January 2010:</p><p>a. was obliged,</p><p>b. but for the operation of an agreement-based transitional instrument or an enterprise agreement would have been obliged, or</p><p>c. if it had been an employer in the industry or of the occupations covered by this award would have been obliged</p></li></ol></li></ol></li></ul><p>by the terms of a transitional minimum wage instrument or an award-based transitional instrument to pay a particular loading or penalty at a lower rate than the equivalent loading or penalty in this award for any classification of employee.</p><ol><li><p>Prior to the first full pay period on or after 1 July 2010 the employer must pay no less than the loading or penalty in the relevant transitional minimum wage instrument or award-based transitional instrument for the classification concerned.</p></li><li><p>The difference between the loading or penalty in this award and the rate in clause A.5.2 is referred to as the transitional percentage.</p></li><li><p>From the following dates the employer must pay no less than the loading or penalty in this award minus the specified proportion of the transitional percentage:</p></li></ol><p><strong>First full pay period on or after</strong></p><hr><p>1 July 2010 80% 1 July 2011 60% 1 July 2012 40% 1 July 2013 20%</p><ol><li><p>These provisions cease to operate from the beginning of the first full pay period on or after 1 July 2014.</p></li><li><p>Loadings and penalty rates -- existing loading or penalty rate higher</p><ol><li><p>The following transitional arrangements apply to an employer which, immediately prior to 1 January 2010:</p><p>a. was obliged,</p><p>b. but for the operation of an agreement-based transitional instrument or an enterprise agreement would have been obliged, or</p><p>c. if it had been an employer in the industry or of the occupations covered by this award would have been obliged</p></li></ol></li></ol><p>by the terms of a transitional minimum wage instrument or an award-based transitional instrument to pay a particular loading or penalty at a higher rate than the equivalent loading or penalty in this award, or to pay a particular loading or penalty and there is no equivalent loading or penalty in this award, for any classification of employee.</p><ol><li><p>Prior to the first full pay period on or after 1 July 2010 the employer must pay no less than the loading or penalty in the relevant transitional minimum wage instrument or award-based transitional instrument.</p></li><li><p>The difference between the loading or penalty in this award and the rate in clause A.6.2 is referred to as the transitional percentage. Where there is no equivalent loading or penalty in this award, the transitional percentage is the rate in A.6.2.</p></li><li><p>From the following dates the employer must pay no less than the loading or penalty in this award plus the specified proportion of the transitional percentage:</p></li></ol><p><strong>First full pay period on or after</strong></p><hr><p>1 July 2010 80% 1 July 2011 60% 1 July 2012 40% 1 July 2013 20%</p><ol><li><p>These provisions cease to operate from the beginning of the first full pay period on or after 1 July 2014.</p></li><li><p>Loadings and penalty rates -- no existing loading or penalty rate</p><ol><li><p>The following transitional arrangements apply to an employer not covered by clause A.5 or A.6 in relation to a particular loading or penalty in this award.</p></li><li><p>Prior to the first full pay period on or after 1 July 2010 the employer need not pay the loading or penalty in this award.</p></li><li><p>From the following dates the employer must pay no less than the following percentage of the loading or penalty in this award:</p></li></ol></li></ol><p><strong>First full pay period on or after</strong></p><hr><p>1 July 2010 20% 1 July 2011 40% 1 July 2012 60% 1 July 2013 80%</p><ol><li><p>These provisions cease to operate from the beginning of the first full pay period on or after 1 July 2014.</p></li><li><p>Former Division 2B employers</p></li><li><p>This clause applies to an employer which, immediately prior to 1 January 2011, was covered by a Division 2B State award.</p></li><li><p>All of the terms of a Division 2B State award applying to a Division 2B employer are continued in effect until the end of the full pay period commencing before 1 February 2011.</p></li><li><p>Subject to this clause, from the first full pay period commencing on or after 1 February 2011 a Division 2B employer must pay no less than the minimum wages, loadings and penalty rates which it would be required to pay under this Schedule if it had been a national system employer immediately prior to 1 January 2010.</p></li><li><p>Despite clause A.8.3, where a minimum wage, loading or penalty rate in a Division 2B State award immediately prior to 1 February 2011 was lower than the corresponding minimum wage, loading or penalty rate in this award, nothing in this Schedule requires a Division 2B employer to pay more than the minimum wage, loading or penalty rate in this award.</p></li><li><p>Despite clause A.8.3, where a minimum wage, loading or penalty rate in a Division 2B State award immediately prior to 1 February 2011 was higher than the corresponding minimum wage, loading or penalty rate in this award, nothing in this Schedule requires a Division 2B employer to pay less than the minimum wage, loading or penalty rate in this award.</p></li><li><p>In relation to a Division 2B employer this Schedule commences to operate from the beginning of the first full pay period on or after 1 January 2011 and ceases to operate from the beginning of the first full pay period on or after 1 July 2014.</p></li><li><p>Allowances</p></li><li><p>Health screen and police clearance allowances</p><p>a. This clause applies to an employer in Western Australia which, immediately prior to 1 January 2010:</p><pre><code>i.  was obliged, or

ii. but for the operation of an agreement-based transitional
    instrument would have been obliged, or

iii. if it had been an employer in the industry or of the
     occupations covered by this award would have been obliged
</code></pre></li></ol><p>by an award-based transitional instrument to pay for or reimburse the cost of an employee undergoing health screening or obtaining a police clearance. The employer continues to be bound to observe such provisions and the employee continues to be entitled to the benefit.</p><p>b. This clause ceases to operate on 31 December 2014.</p>`,52)])])}const y=a(o,[["render",r]]);export{u as __pageData,y as default};
